parameters.jsCode:
const raw = items[0];

// Claude output is in content[0].text
const rawText = raw.json.content[0].text;

let cleaned = rawText
  .replace(/```json\n?/gi, '')
  .replace(/```\n?/gi, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  return [{ json: {
    parse_error: true,
    error_message: e.message,
    raw_text: rawText.substring(0, 500)
  }}];
}

const flag = (parsed.program_area === "UNKNOWN" || parsed.region === "UNKNOWN")
  ? true
  : (parsed.human_review_flag ?? false);

const reason = (parsed.program_area === "UNKNOWN" || parsed.region === "UNKNOWN")
  ? "Program area or region is UNKNOWN — manual classification required"
  : (parsed.human_review_reason ?? null);

return [{
  json: {
    original_input_mode:     parsed.original_input_mode     ?? "Research Question",
    original_question:       parsed.original_question       ?? "UNKNOWN",
    refined_question:        parsed.refined_question        ?? "UNKNOWN",
    program_area:            parsed.program_area            ?? "UNKNOWN",
    region:                  parsed.region                  ?? "UNKNOWN",
    audience:                parsed.audience                ?? "UNKNOWN",
    urgency:                 parsed.urgency                 ?? "Standard",
    extraction_confidence:   parsed.extraction_confidence   ?? "LOW",
    human_review_flag:       flag,
    human_review_reason:     reason,
    sub_questions:           parsed.sub_questions           ?? [],
    search_queries:          parsed.search_queries          ?? [],
    academic_search_queries: parsed.academic_search_queries ?? [],
    expected_source_types:   parsed.expected_source_types   ?? [],
    quality_threshold:       parsed.quality_threshold       ?? "HIGH"
  }
}];

const raw = items[0];

// Get trigger_id if this came from meeting pipeline
// If manual form submission, generate one from question + timestamp
const question = raw.json.original_question ?? "unknown";
const timestamp = new Date().toISOString();
const triggerId = raw.json.trigger_id ?? 
  (question.substring(0, 40) + "-" + timestamp).replace(/\s+/g, '-');

return [{
  json: {
    ...raw.json,
    trigger_id: triggerId,
    iteration_count: 0,
    max_iterations: 2,
    duplicate: false
  }
}];

const d = items[0].json;

const userMessage = d.search_queries[0]
  + '. Also search for: ' + d.search_queries[1]
  + '. And: ' + d.search_queries[2]
  + '. Context: This is for a ' + d.audience
  + ' on ' + d.program_area
  + ' in ' + d.region
  + '. Refined question: ' + d.refined_question;

return [{
  json: {
    ...d,
    request_body: {
      model: "sonar",
      messages: [
        {
          role: "system",
          content: "You are a global health research assistant for [Your Organization]. Search for credible recent evidence from WHO, peer-reviewed journals, USAID, Malaria Consortium, and NGO sources. Include source URLs and publication dates. Prioritize 2023-2024 sources."
        },
        {
          role: "user",
          content: userMessage
        }
      ],
      max_tokens: 2000,
      temperature: 0.2,
      search_context_size: "high"
    }
  }
}];

// HTTP node output lost the planning data — pull it back from the last Code node
const planning = $('Loop Counter + Idempotency').first().json;
const httpResponse = items[0].json;

const userMessage = planning.academic_search_queries[0]
  + '. Also search: ' + (planning.academic_search_queries[1] ?? planning.academic_search_queries[0])
  + '. Focus on peer-reviewed journals, systematic reviews, RCTs and WHO reports for a '
  + planning.audience + ' brief on ' + planning.program_area + ' in ' + planning.region;

return [{
  json: {
    ...planning,
    web_result: httpResponse,
    request_body: JSON.stringify({
      model: "sonar-pro",
      messages: [
        {
          role: "system",
          content: "You are an academic research specialist for [Your Organization]. Search exclusively for peer-reviewed publications, systematic reviews, meta-analyses, Cochrane reviews, WHO technical reports, and RCTs directly related to the topic. Include full title, journal, year, and URL for every source. Prioritize 2022 onwards."
        },
        {
          role: "user",
          content: userMessage
        }
      ],
      max_tokens: 2000,
      temperature: 0.1,
      search_context_size: "high"
    })
  }
}];

// Academic HTTP response is in items[0].json
const academicRaw = items[0].json;

// Pull planning data from Loop Counter — always has all fields intact
const planningData = $('Loop Counter + Idempotency').first().json;

// Pull web result directly from the Web HTTP node
const webRaw = $('Call Perplexity Web').first().json;
const webItem = {
  choices:   webRaw.choices   ?? [],
  citations: webRaw.citations ?? []
};

const academicItem = {
  choices:        academicRaw.choices        ?? [],
  citations:      academicRaw.citations      ?? [],
  search_results: academicRaw.search_results ?? []
};

const webContent      = webItem?.choices?.[0]?.message?.content ?? "No web results found";
const webCitations    = webItem?.citations ?? [];

const academicContent = academicItem.choices?.[0]?.message?.content ?? "No academic results found";
const academicCitations = academicItem.citations ?? [];
const academicSources   = academicItem.search_results ?? [];

const allCitations = [...new Set([...webCitations, ...academicCitations])];

const allSources = academicSources.length > 0
  ? academicSources
  : allCitations.map((url, i) => ({
      url,
      title: "Source " + (i + 1),
      date: "2026",
      snippet: ""
    }));

const structuredSources = allSources.map((s, i) => ({
  number: i + 1,
  title: s.title ?? "Unknown",
  url: s.url ?? "",
  publication_date: s.date ?? "Unknown",
  source_type:
    !s.url                          ? "Unknown" :
    s.url.includes("who.int")       ? "WHO / Multilateral" :
    s.url.includes("pubmed") ||
    s.url.includes("pmc.ncbi")      ? "Peer-reviewed Journal" :
    s.url.includes("cochrane")      ? "Systematic Review" :
    s.url.includes("thelancet") ||
    s.url.includes("bmj") ||
    s.url.includes("plos") ||
    s.url.includes("nature.com") ||
    s.url.includes("sciencedirect") ||
    s.url.includes("springer") ||
    s.url.includes("oxford") ||
    s.url.includes("wiley") ||
    s.url.includes("elsevier") ||
    s.url.includes("nejm.org") ||
    s.url.includes("jamanetwork") ||
    s.url.includes("academic.oup")  ? "Peer-reviewed Journal" :
    s.url.includes("usaid") ||
    s.url.includes("pmi") ||
    s.url.includes("givewell")      ? "Donor / Government" :
    s.url.includes("unicef") ||
    s.url.includes("worldbank")     ? "WHO / Multilateral" :
                                      "NGO / Programme Report",
  region_relevance: "To be assessed",
  snippet: s.snippet ?? ""
}));

return [{
  json: {
    original_input_mode:     planningData.original_input_mode     ?? "Research Question",
    original_question:       planningData.original_question       ?? "",
    refined_question:        planningData.refined_question        ?? "",
    program_area:            planningData.program_area            ?? "UNKNOWN",
    region:                  planningData.region                  ?? "UNKNOWN",
    audience:                planningData.audience                ?? "UNKNOWN",
    urgency:                 planningData.urgency                 ?? "Standard",
    extraction_confidence:   planningData.extraction_confidence   ?? "LOW",
    human_review_flag:       planningData.human_review_flag       ?? false,
    human_review_reason:     planningData.human_review_reason     ?? null,
    iteration_count:         planningData.iteration_count         ?? 0,
    max_iterations:          planningData.max_iterations          ?? 2,
    trigger_id:              planningData.trigger_id              ?? "",
    sub_questions:           planningData.sub_questions           ?? [],
    search_queries:          planningData.search_queries          ?? [],
    academic_search_queries: planningData.academic_search_queries ?? [],
    quality_threshold:       planningData.quality_threshold       ?? "HIGH",
    web_search_content:      webContent,
    academic_search_content: academicContent,
    all_citations:           allCitations,
    structured_sources:      structuredSources,
    total_sources_found:     allCitations.length
  }
}];

