// Pull the raw text output from Evidence Synthesizer
const synthOutput = $('Evidence Synthesizer').first().json;

let rawText = '';
if (synthOutput?.content?.[0]?.text) {
  rawText = synthOutput.content[0].text;
} else if (synthOutput?.text) {
  rawText = synthOutput.text;
} else {
  throw new Error('Evidence Synthesizer produced no output. Keys found: ' + JSON.stringify(Object.keys(synthOutput || {})));
}

rawText = rawText.trim();

// ── PARSE THE METADATA HEADER ──────────────────────────────────────────────
// Format is:
//   TITLE: ...
//   CONFIDENCE: HIGH/MEDIUM/LOW
//   CONFIDENCE_REASON: ...
//   KEY_TAKEAWAY: ...
//   SLACK_BULLETS:
//   • bullet 1
//   • bullet 2
//   • bullet 3
//   • bullet 4
//   • bullet 5
//   ---
//   [full report body]

function extractLine(text, label) {
  const regex = new RegExp('^' + label + ':(.+)$', 'mi');
  const match = text.match(regex);
  return match ? match[1].trim() : '';
}

// Extract the separator position
const separatorIndex = rawText.indexOf('\n---');
const headerText = separatorIndex > -1 ? rawText.substring(0, separatorIndex) : rawText;
const briefBody  = separatorIndex > -1 ? rawText.substring(separatorIndex + 4).trim() : rawText;

const briefTitle       = extractLine(headerText, 'TITLE');
const confidenceLevel  = extractLine(headerText, 'CONFIDENCE');
const confidenceReason = extractLine(headerText, 'CONFIDENCE_REASON');
const keyTakeaway      = extractLine(headerText, 'KEY_TAKEAWAY');

// Extract slack bullets — everything between SLACK_BULLETS: and ---
const bulletMatch = headerText.match(/SLACK_BULLETS:\s*\n([\s\S]*?)(?:\n---|$)/i);
const slackBullets = bulletMatch ? bulletMatch[1].trim() : '';

// Fallbacks if parsing failed
const title    = briefTitle    || 'PATH Research Brief';
const confLvl  = confidenceLevel.toUpperCase().includes('HIGH')   ? 'HIGH'
               : confidenceLevel.toUpperCase().includes('MEDIUM') ? 'MEDIUM'
               : confidenceLevel.toUpperCase().includes('LOW')    ? 'LOW'
               : 'MEDIUM';

// Get planning data for all other fields
const planningData = $('Parse Evaluator').first().json;

return [{
  json: {
    ...planningData,
    // Brief content
    brief_title:       title,
    confidence_level:  confLvl,
    confidence_reason: confidenceReason || planningData.evaluation_notes || '',
    brief_body:        briefBody || rawText,
    key_takeaway:      keyTakeaway || '',
    slack_bullets:     slackBullets || '',
    // Pass raw text for doc writing
    full_report_text:  rawText
  }
}];

const d = items[0].json;

// Build source type distribution
const sourceTypes = {};
(d.structured_sources ?? []).forEach(s => {
  const t = s.source_type ?? "Unknown";
  sourceTypes[t] = (sourceTypes[t] ?? 0) + 1;
});

const labels = Object.keys(sourceTypes);
const values = Object.values(sourceTypes);

const chartConfig = {
  type: "doughnut",
  data: {
    labels: labels,
    datasets: [{
      data: values,
      backgroundColor: [
        "#2563EB", "#16A34A", "#D97706", "#DC2626", "#7C3AED", "#0891B2"
      ]
    }]
  },
  options: {
    plugins: {
      title: {
        display: true,
        text: "Evidence Sources: " + d.program_area + " — " + d.region
      },
      legend: { position: "bottom" }
    }
  }
};

const encoded = encodeURIComponent(JSON.stringify(chartConfig));
const chartUrl = "https://quickchart.io/chart?c=" + encoded + "&width=500&height=300";

return [{
  json: {
    ...d,
    chart_url: chartUrl
  }
}];

const d = items[0].json;
const today = new Date().toISOString().split('T')[0];

// Build the document — the brief_body is already well-structured markdown
// We add a clean header block above it
const header = 
`PATH RESEARCH BRIEF
Generated by the Evidence Intelligence Engine
════════════════════════════════════════════════════

Date:          ${today}
Program Area:  ${d.program_area}
Region:        ${d.region}
Audience:      ${d.audience}
Urgency:       ${d.urgency}
Confidence:    ${d.confidence_level} — ${d.confidence_reason}
Sources Found: ${d.total_sources_found}
Search Rounds: ${d.iteration_count}
Human Review:  ${d.human_review_flag ? '⚠ REQUIRED — ' + (d.human_review_reason || '') : '✓ Not required'}

Original Question:
${d.original_question}

Refined Question:
${d.refined_question}

════════════════════════════════════════════════════

`;

// The brief body from Claude is clean markdown prose
// Google Docs will render the plain text — headings won't render as headings
// but the structure will be clear and readable
const docContent = header + d.brief_body;

return [{
  json: {
    ...d,
    doc_content: docContent
  }
}];

const docData   = items[0].json;
