const input = $input.first().json;
const body = input.body || input;

return [{
  json: {
    "Input Mode": body["Input Mode"] || body.input_mode || "Research Question",
    "Research Question": body["Research Question"] || body.research_question || "",
    "Meeting Transcript": body["Meeting Transcript"] || body.meeting_transcript || "",
    "Program Area": body["Program Area"] || body.program_area || "Unknown",
    "Geographic Region": body["Geographic Region"] || body.geographic_region || body.region || "",
    "Audience Type": body["Audience Type"] || body.audience_type || body.audience || "Donor Brief",
    "Urgency": body["Urgency"] || body.urgency || "Standard"
  }
}];

// Get all emails from the sheet
const attendees = $input.all();
const emails = attendees
  .map(item => item.json.Email)
  .filter(email => email && email.includes('@'))
  .join(', ');

// Carry forward ALL research data
const researchData = $('Attach Content to Doc ID').item.json;

return [{
  json: {
    ...researchData,
    attendee_emails: emails
  }
}];
